import{_ as t,o,c as i,ak as n}from"./chunks/framework.Bb9ZXUwF.js";const h=JSON.parse('{"title":"Shared tooling and configuration","description":"","frontmatter":{},"headers":[],"relativePath":"shared-tooling.md","filePath":"shared-tooling.md"}'),a={name:"shared-tooling.md"};function s(r,e,d,c,l,p){return o(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="shared-tooling-and-configuration" tabindex="-1">Shared tooling and configuration <a class="header-anchor" href="#shared-tooling-and-configuration" aria-label="Permalink to “Shared tooling and configuration”">​</a></h1><h2 id="what-is-centralized-at-the-repository-root" tabindex="-1">What is centralized at the repository root <a class="header-anchor" href="#what-is-centralized-at-the-repository-root" aria-label="Permalink to “What is centralized at the repository root”">​</a></h2><p>These files intentionally live once at the <strong>monorepo root</strong> and apply to all (or most) packages:</p><table tabindex="0"><thead><tr><th>Area</th><th>Examples</th></tr></thead><tbody><tr><td><strong>JavaScript / Node</strong></td><td>Root <code>package.json</code> scripts, <code>pnpm-workspace.yaml</code>, shared <code>typescript</code> / <code>@wordpress/scripts</code> versions</td></tr><tr><td><strong>Linting</strong></td><td><code>.eslintrc</code> (or equivalent), <code>.stylelintrc</code>, <code>.prettierrc.js</code>, markdown lint config, <code>phpcs.xml</code> via Composer at root</td></tr><tr><td><strong>Testing</strong></td><td>Shared Playwright setup under <code>packages/e2e/</code>, PHPUnit XML in <code>packages/phpunit-config/</code></td></tr><tr><td><strong>Git</strong></td><td>Root <code>.gitignore</code>; release export rules often use <code>.gitattributes</code> per package</td></tr></tbody></table><p>Run <strong>monorepo-wide</strong> checks from the root, for example:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lint</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # JS, CSS, PHP, MD, package.json (see root package.json)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # all projects with a build target</span></span></code></pre></div><h2 id="what-stays-package-specific" tabindex="-1">What stays package-specific <a class="header-anchor" href="#what-stays-package-specific" aria-label="Permalink to “What stays package-specific”">​</a></h2><p>Keep configuration <strong>in the package</strong> when it encodes product behavior:</p><ul><li><strong><code>block.json</code></strong>, theme <code>theme.json</code>, WordPress templates, and PHP bootstrap files</li><li><strong><code>.wp-env.json</code></strong> — port mappings, plugin/theme mappings, and env-specific options</li><li><strong><code>composer.json</code></strong> — package name, autoload namespaces, <code>require</code> / <code>require-dev</code> for that product</li><li><strong><code>project.json</code></strong> — which Nx targets the package implements and <code>implicitDependencies</code></li><li><strong>E2E specs</strong> under <code>tests/e2e/</code> and screenshots under <code>tests/screenshot/</code> (generator conventions)</li></ul><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to “Examples”">​</a></h2><h3 id="linting" tabindex="-1">Linting <a class="header-anchor" href="#linting" aria-label="Permalink to “Linting”">​</a></h3><ul><li><strong>JavaScript:</strong> <code>pnpm lint-js</code> → <code>wp-scripts lint-js</code> using root ESLint config; fix with <code>pnpm fix-js</code>.</li><li><strong>CSS/SCSS:</strong> <code>pnpm lint-css</code> → <code>wp-scripts lint-style</code>; fix with <code>pnpm fix-css</code>.</li><li><strong>PHP:</strong> <code>pnpm lint-php</code> → root Composer <code>lint-php</code> (PHPCS); fix with <code>pnpm fix-php</code>.</li><li><strong>Markdown:</strong> <code>pnpm lint-md</code> for docs; <code>pnpm fix-md</code> for autofix.</li></ul><h3 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to “Testing”">​</a></h3><ul><li><strong>E2E:</strong> <code>npx nx run &lt;project&gt;:test-e2e</code> (depends on <code>wp-env-start</code> and upstream <code>build</code> per <code>nx.json</code>).</li><li><strong>PHP integration:</strong> <code>npx nx run &lt;project&gt;:test-integration</code> runs PHPUnit inside <code>wp-env</code> using shared config from <code>packages/phpunit-config</code>.</li></ul><h3 id="build" tabindex="-1">Build <a class="header-anchor" href="#build" aria-label="Permalink to “Build”">​</a></h3><ul><li><strong>Production assets:</strong> <code>npx nx run &lt;project&gt;:build</code> → <code>wp-scripts build</code>, output typically <code>dist/</code>.</li></ul><h2 id="migration-expectation-remove-redundant-configuration" tabindex="-1">Migration expectation: remove redundant configuration <a class="header-anchor" href="#migration-expectation-remove-redundant-configuration" aria-label="Permalink to “Migration expectation: remove redundant configuration”">​</a></h2><p>When importing a standalone repository:</p><ul><li>Delete duplicate lint configs, per-repo GitHub Actions, and redundant Prettier/Stylelint files <strong>unless</strong> the monorepo root cannot express a needed exception.</li><li>If a one-off rule is required, prefer the <strong>smallest local override</strong> documented in a comment or package readme rather than forking entire configs.</li></ul><h2 id="documentation-site-tooling" tabindex="-1">Documentation site tooling <a class="header-anchor" href="#documentation-site-tooling" aria-label="Permalink to “Documentation site tooling”">​</a></h2><p>The docs portal uses <strong>VitePress</strong> and a sync script (<code>tools/sync-docs.mjs</code>). Package docs remain in <code>plugins/&lt;slug&gt;/docs/</code> and <code>themes/&lt;slug&gt;/docs/</code>. See <a href="./documentation-site">Documentation site</a>.</p>`,21)])])}const u=t(a,[["render",s]]);export{h as __pageData,u as default};
